const fs = require('fs');
const path = require('path');

const item = $input.first().json;
const filePath = item.path;

let content = '';
try {
  content = fs.readFileSync(filePath, 'utf8');
} catch (e) {
  // Wait briefly and retry once (file may still be writing)
  await new Promise(r => setTimeout(r, 500));
  content = fs.readFileSync(filePath, 'utf8');
}

// Parse frontmatter
const frontmatterMatch = content.match(/^---\n([\s\S]*?)\n---/);
let frontmatter = {};
if (frontmatterMatch) {
  const lines = frontmatterMatch[1].split('\n');
  for (const line of lines) {
    const [key, ...val] = line.split(':');
    if (key && val.length) {
      frontmatter[key.trim()] = val.join(':').trim().replace(/^"|"$/g, '');
    }
  }
}

return [{
  json: {
    ...item,
    fileContent: content,
    frontmatter: frontmatter,
    courseName: frontmatter.course || path.basename(path.dirname(filePath)),
    noteType: frontmatter.type || 'general',
    noteDate: frontmatter.date || new Date().toISOString().split('T')[0]
  }
}];

const fs = require('fs');
const path = require('path');

const item = $input.first().json;
const vaultPath = process.env.OBSIDIAN_VAULT_PATH;
const courseName = item.courseName;
const fileName = item.fileName.replace('.md', '');

// Path to the course MOC (Map of Content) index file
const mocPath = path.join(vaultPath, courseName, `${courseName} - Index.md`);

let mocContent = '';
let mocExists = false;

try {
  mocContent = fs.readFileSync(mocPath, 'utf8');
  mocExists = true;
} catch (e) {
  // MOC doesn't exist yet, create it
  mocContent = `---\ntype: moc\ncourse: "${courseName}"\ncreated: ${new Date().toISOString().split('T')[0]}\ntags: [${courseName}, moc, index]\n---\n\n# ${courseName} - Course Index\n\n## 📚 Notes\n\n## 📝 Lecture Notes\n\n## 📋 Assignments\n\n## 🧪 Tutorials\n`;
}

// Check if note is already linked
const noteLink = `[[${fileName}]]`;
const alreadyLinked = mocContent.includes(noteLink);

let updatedMoc = mocContent;
if (!alreadyLinked) {
  const noteType = item.noteType || 'general';
  let section = '## 📚 Notes';
  if (noteType.includes('lecture')) section = '## 📝 Lecture Notes';
  else if (noteType.includes('assignment')) section = '## 📋 Assignments';
  else if (noteType.includes('tutorial')) section = '## 🧪 Tutorials';

  const insertLine = `- ${noteLink} - ${item.noteDate || new Date().toISOString().split('T')[0]}`;
  updatedMoc = mocContent.replace(section, `${section}\n${insertLine}`);
}

fs.writeFileSync(mocPath, updatedMoc, 'utf8');

return [{
  json: {
    ...item,
    mocPath: mocPath,
    mocUpdated: !alreadyLinked,
    mocCreated: !mocExists
  }
}];

const fs = require('fs');
const path = require('path');

const item = $input.first().json;
const vaultPath = process.env.OBSIDIAN_VAULT_PATH;
const today = new Date().toISOString().split('T')[0];
const fileName = item.fileName.replace('.md', '');

// Path to daily note
const dailyNotePath = path.join(vaultPath, 'Daily Notes', `${today}.md`);

let dailyContent = '';
try {
  dailyContent = fs.readFileSync(dailyNotePath, 'utf8');
} catch (e) {
  // Create daily note if it doesn't exist
  dailyContent = `---\ndate: ${today}\ntype: daily-note\ntags: [daily]\n---\n\n# ${today}\n\n## 📥 New Materials Today\n\n## ✅ Tasks\n\n## 📓 Notes\n\n## 🔗 Links\n`;
}

// Add entry to daily note under New Materials
const newEntry = `- [[${fileName}]] (${item.courseName || 'Unknown Course'})`;
if (!dailyContent.includes(newEntry)) {
  dailyContent = dailyContent.replace(
    '## 📥 New Materials Today',
    `## 📥 New Materials Today\n${newEntry}`
  );
}

// Ensure directory exists
const dailyDir = path.dirname(dailyNotePath);
if (!fs.existsSync(dailyDir)) fs.mkdirSync(dailyDir, { recursive: true });

fs.writeFileSync(dailyNotePath, dailyContent, 'utf8');

return [{
  json: {
    ...item,
    dailyNotePath: dailyNotePath,
    dailyNoteUpdated: true
  }
}];

const fs = require('fs');
const path = require('path');

const item = $input.first().json;
const vaultPath = process.env.OBSIDIAN_VAULT_PATH;

// Update a master graph/dashboard file
const dashboardPath = path.join(vaultPath, 'Dashboard.md');

let dashboard = '';
try {
  dashboard = fs.readFileSync(dashboardPath, 'utf8');
} catch (e) {
  dashboard = `---\ntype: dashboard\ntags: [dashboard, home]\n---\n\n# 🎓 Study Dashboard\n\n## 📊 Stats\n- **Total Notes**: 0\n- **Last Updated**: never\n\n## 📚 Courses\n\n## 🗓️ Recent Activity\n`;
}

// Update last updated timestamp
const now = new Date();
const ts = now.toISOString().replace('T', ' ').slice(0, 16);
dashboard = dashboard.replace(/\*\*Last Updated\*\*: .*/,  `**Last Updated**: ${ts}`);

// Increment note count
const countMatch = dashboard.match(/\*\*Total Notes\*\*: (\d+)/);
if (countMatch) {
  const newCount = parseInt(countMatch[1]) + 1;
  dashboard = dashboard.replace(/\*\*Total Notes\*\*: \d+/, `**Total Notes**: ${newCount}`);
}

// Add course if not already listed
const courseName = item.courseName || 'Unknown';
if (!dashboard.includes(`[[${courseName} - Index]]`)) {
  dashboard = dashboard.replace(
    '## 📚 Courses',
    `## 📚 Courses\n- [[${courseName} - Index]]`
  );
}

// Add to recent activity
const fileName = item.fileName.replace('.md', '');
const recentEntry = `- ${ts} → [[${fileName}]] (${courseName})`;
dashboard = dashboard.replace(
  '## 🗓️ Recent Activity',
  `## 🗓️ Recent Activity\n${recentEntry}`
);

fs.writeFileSync(dashboardPath, dashboard, 'utf8');

return [{
  json: {
    ...item,
    dashboardUpdated: true,
    integrationComplete: true
  }
}];
